window.SabiloreTracking=(()=>{let i=(e,t,a,n)=>{try{"function"==typeof fbq&&fbq("track",e,{currency:"BDT",...t})}catch(t){console.error(`[Tracking] FB ${e}:`,t)}try{"function"==typeof gtag&&gtag("event",a,{currency:"BDT",...n})}catch(t){console.error(`[Tracking] GA ${a}:`,t)}};return{trackPageView(t){try{"function"==typeof fbq&&fbq("track","PageView")}catch(t){console.error("[Tracking] FB PageView:",t)}try{"function"==typeof gtag&&gtag("event","page_view",{page_title:t,page_location:window.location.href,page_path:window.location.pathname})}catch(t){console.error("[Tracking] GA page_view:",t)}},trackViewContent(t){i("ViewContent",{content_name:t.name,content_category:t.category_name,content_ids:[t.id],content_type:"product",value:t.price},"view_item",{value:t.price,items:[{item_id:t.id,item_name:t.name,item_category:t.category_name,price:t.price}]})},trackAddToCart(t){i("AddToCart",{content_name:t.name,content_ids:[t.id],content_type:"product",value:t.price},"add_to_cart",{value:t.price*(t.quantity||1),items:[{item_id:t.id,item_name:t.name,price:t.price,quantity:t.quantity||1}]})},trackPurchase({transaction_id:t,value:e,items:a=[]}){var n=a.map(t=>({id:t.id||t.product_id,quantity:t.quantity}));i("Purchase",{content_ids:n.map(t=>t.id),content_type:"product",contents:n,value:e},"purchase",{transaction_id:t,value:e,items:a.map(t=>({item_id:t.id||t.product_id,item_name:t.name||"Product",price:t.price,quantity:t.quantity}))})}}})();